import widgetCardStylesText from '../widget-card.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { navigate } from '../../../router.js';
import { createWidgetStatusMixin } from '../../_shared/widget-status.js';
import { HealthService } from '../../../services/health.service.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { safeExec } from '../../../utils/safe-exec.js';

const widgetCardStyles = cssStyleSheet(widgetCardStylesText);
const log = createComponentLogger('home/health-summary-widget');

const template = document.createElement('template');
template.innerHTML = `
    <div class="widget-header">
        <h2 class="widget-title">Health</h2>
    </div>
    <div class="widget-body" id="body"></div>
`;

export class HealthSummaryWidget extends HTMLElement {
    private status!: ReturnType<typeof createWidgetStatusMixin>;

    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
        this.status = createWidgetStatusMixin(this);
        this.shadowRoot!.adoptedStyleSheets = [widgetCardStyles];
        this.shadowRoot!.appendChild(template.content.cloneNode(true));
        this.style.setProperty('--widget-color', 'var(--color-health, #e6b800)');
    }

    setLoading() { this.status.setLoading(); }
    setError(err: unknown) { this.status.setError(err); }
    clearStatus() { this.status.clearStatus(); }

    connectedCallback() {
        this.addEventListener('click', () => navigate('/health'));
        this.refresh();
    }

    async refresh() {
        await safeExec(this, log, () => this.loadData());
    }

    private async loadData() {
        const body = this.shadowRoot!.getElementById('body')!;
        body.textContent = '';

        // @ts-ignore - Temporal is polyfilled in tests
        const today = Temporal.Now.plainDateISO().toString();
        const [nutrition] = await HealthService.fetchNutritionSummary(today, today);
        
        const kcal = nutrition?.total_calories ?? 0;
        const p = document.createElement('p');
        p.textContent = `${kcal} kcal today`;
        body.appendChild(p);
    }
}

if (!customElements.get('health-summary-widget')) {
    customElements.define('health-summary-widget', HealthSummaryWidget);
}
