import '../health-summary-widget/health-summary-widget.component.js';
import '../social-summary-widget/social-summary-widget.component.js';
import '../learn-summary-widget/learn-summary-widget.component.js';
import '../projects-summary-widget/projects-summary-widget.component.js';
import '../home-footer/home-footer.component.js';

const template = document.createElement('template');
template.innerHTML = `
    <header class="home-header">
        <h1 class="home-title">Motivation</h1>
    </header>
    <main class="section-grid">
        <health-summary-widget id="section-card-health"></health-summary-widget>
        <social-summary-widget id="section-card-social"></social-summary-widget>
        <learn-summary-widget id="section-card-vietnamese"></learn-summary-widget>
        <projects-summary-widget id="section-card-projects"></projects-summary-widget>
    </main>
    <home-footer class="home-footer"></home-footer>
`;

export class HomeScreen extends HTMLElement {
    private readonly handleVisibilityChange = () => {
        if (document.visibilityState === 'visible') {
            this.refreshWidgets();
        }
    };

    private ensureContent(): void {
        if (!this.firstChild) {
            this.appendChild(template.content.cloneNode(true));
        }
    }

    connectedCallback() {
        this.ensureContent();
        document.addEventListener('visibilitychange', this.handleVisibilityChange);
    }

    disconnectedCallback() {
        document.removeEventListener('visibilitychange', this.handleVisibilityChange);
    }

    private refreshWidgets() {
        const widgets = this.querySelectorAll<any>(
            'health-summary-widget, social-summary-widget, learn-summary-widget, projects-summary-widget'
        );
        widgets.forEach(w => {
            if (typeof w.refresh === 'function') {
                w.refresh();
            }
        });
    }
}

if (!customElements.get('home-screen')) {
    customElements.define('home-screen', HomeScreen);
}
